package org.blogs.Blogs.repository;import org.blogs.Blogs.entity.BlogPost;import org.blogs.Blogs.entity.BlogView;import org.blogs.Blogs.entity.UserEntity;import org.springframework.data.jpa.repository.JpaRepository;public interface BlogViewRepository extends JpaRepository<BlogView, Long> {    boolean existsByBlogAndUser(BlogPost blog, UserEntity user);    boolean existsByBlogAndIpAddress(BlogPost blog, String ipAddress);    long countByBlog(BlogPost blog);}